}

bool PingMessage::Deserialize(const uint8_t*& data) {
    std::memcpy(&timestamp, data, sizeof(timestamp)); data += sizeof(timestamp);
    std::memcpy(&nonce, data, sizeof(nonce)); data += sizeof(nonce);
