{"content":"/**
 * @file InputHandler.h
 * @brief 输入处理器 - 键盘 (WASD) 与鼠标输入管理
 *
 * 本文件定义 InputHandler 类，负责：
 * 1. 捕获 Windows 键盘输入 (WASD 键)
 * 2. 将按键状态转换为游戏输入 (PlayerInput)
 * 3. 支持持续按键状态跟踪（用于平滑移动）
 * 4. 可选鼠标视角控制
 *
 * 使用示例：
 * @code
 *   InputHandler handler;
 *   handler.init(hwnd); // 初始化 Windows 句柄
 *   // 在游戏循环中：
 *   handler.update();
 *   PlayerInput input = handler.getInput();
 * @endcode
 */

#pragma once

#include "../common/physics_state.h"
#include <cstdint>
#include <functional>
#include <string>

// Windows 前置声明
#ifdef _WIN32
    // 不需要完整包含 windows.h，使用前向声明即可
    struct HINSTANCE__*;
    using HINSTANCE = HINSTANCE__*;
    using HWND = void*;
#endif

namespace PhysicsSync {

// ================================================================
// 输入配置
// ================================================================

/**
 * @brief 输入处理器配置
 */
struct InputConfig {
    /// 移动速度因子
    float moveSpeed = 5.0f;
    /// 视角旋转灵敏度
    float lookSensitivity = 0.002f;
    /// 最大移动速度
    float maxMoveSpeed = 10.0f;

    InputConfig() = default;
};

// ================================================================
// 按键状态
// ================================================================

/**
 * @brief 按键状态枚举
 */
enum class KeyState {
    UP,       ///< 按键抬起
    DOWN,     ///< 按键按下（仅在按下的那一帧）
    HELD,     ///< 按键持续按住
};

// ================================================================
// Windows 窗口过程回调
// ================================================================

/**
 * @brief Windows 窗口过程回调类型
 *
 * 用于接收 Windows 消息并转换为输入事件。
 * 在 Windows 平台上，输入处理器通过此回调处理 WM_KEYDOWN/WM_KEYUP 消息。
 */
using WndProcCallback = std::function<bool(void* hwnd, uint32_t msg,
                                            uint64_t wParam, int64_t lParam)>;

// ================================================================
// 输入处理器
// ================================================================

/**
 * @brief 跨平台输入处理器
 *
 * 负责：
 * 1. 跟踪按键状态（上/下/持续）
 * 2. 将按键映射到游戏输入
 * 3. 提供平滑的移动和视角控制
 *
 * 在 Windows 上，使用 Win32 API 处理键盘消息。
 * 非 Windows 平台使用简化实现（通过回调接收输入）。
 */
class InputHandler {
public:
    /// 构造函数
    InputHandler();

    /// 析构函数
    ~InputHandler();

    // 禁止拷贝
    InputHandler(const InputHandler&) = delete;
    InputHandler& operator=(const InputHandler&) = delete;

    /**
     * @brief 初始化输入处理器
     * @param config 输入配置
     * @return 是否成功初始化
     */
    bool initialize(const InputConfig& config = InputConfig());

    /**
     * @brief 销毁输入处理器资源
     */
    void destroy();

    // ================================================================
    // 输入更新
    // ================================================================

    /**
     * @brief 更新输入状态
     *
     * 必须在每帧调用此方法以更新按键状态。
     * 在 Windows 上，此方法在窗口过程中被间接调用。
     */
    void update();

    /**
     * @brief 处理 Windows 窗口消息
     * @param msg 消息类型（WM_KEYDOWN, WM_KEYUP 等）
     * @param wParam 第一个消息参数（虚拟键码等）
     * @param lParam 第二个消息参数（重复计数、扫描码等）
     *
     * 在 Windows 上，将此函数作为回调传递给窗口过程。
     */
    void handleWindowsMessage(uint32_t msg, uint64_t wParam, int64_t lParam);

    // ================================================================
    // 输入查询
    // ================================================================

    /**
     * @brief 获取当前游戏输入
     * @return PlayerInput 结构体
     *
     * 将按键状态转换为标准的 PlayerInput。
     * moveX/moveY 范围 [-1.0, 1.0]。
     */
    PlayerInput getCurrentInput() const;

    /**
     * @brief 获取按键状态
     * @param key 虚拟键码 (VK_W, VK_A, VK_S, VK_D 等)
     * @return 按键状态
     */
    KeyState getKeyState(uint8_t key) const;

    /**
     * @brief 检查按键是否按下（包括持续按住）
     * @param key 虚拟键码
     * @return 按下返回 true
     */
    bool isKeyDown(uint8_t key) const;

    /**
     * @brief 检查按键是否在当前帧被按下
     * @param key 虚拟键码
     * @return 按下返回 true（仅在按下的那一帧）
     */
    bool isKeyJustPressed(uint8_t key) const;

